import{_ as e,o,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Mobile Technology","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/mobile-tech.md","filePath":"theory/systems/mobile-tech.md"}'),d={name:"theory/systems/mobile-tech.md"};function i(s,t,n,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="mobile-technology" tabindex="-1">Mobile Technology <a class="header-anchor" href="#mobile-technology" aria-label="Permalink to &quot;Mobile Technology&quot;">​</a></h1><p>Mobile technology has transformed how we communicate, work, learn, and entertain ourselves. A device in your pocket has more computing power than the computers that landed humans on the moon — and it is always connected.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Mobile technology is primarily a Grade 12 topic, though mobile devices are introduced in Grade 10 as a type of computer. Grade 12 focus: advantages/limitations of mobile, 4G/5G, mobile OS, mobile security.</p></div><hr><h2 id="what-is-mobile-technology" tabindex="-1">What is Mobile Technology? <a class="header-anchor" href="#what-is-mobile-technology" aria-label="Permalink to &quot;What is Mobile Technology?&quot;">​</a></h2><p><strong>Mobile technology</strong> refers to portable computing devices and the wireless networks that connect them, enabling communication and computing from any location.</p><hr><h2 id="mobile-devices" tabindex="-1">Mobile Devices <a class="header-anchor" href="#mobile-devices" aria-label="Permalink to &quot;Mobile Devices&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Device</th><th>Description</th><th>Typical OS</th></tr></thead><tbody><tr><td><strong>Smartphone</strong></td><td>Phone with advanced computing (apps, internet, camera, GPS)</td><td>Android, iOS</td></tr><tr><td><strong>Feature phone</strong></td><td>Basic phone — calls and SMS only, no apps</td><td>Proprietary OS</td></tr><tr><td><strong>Tablet</strong></td><td>Larger touchscreen device, no built-in phone</td><td>Android, iPadOS, Windows</td></tr><tr><td><strong>Smartwatch</strong></td><td>Wrist-worn computer — health tracking, notifications</td><td>Wear OS, watchOS</td></tr><tr><td><strong>Fitness tracker</strong></td><td>Wearable measuring steps, heart rate, sleep</td><td>Proprietary</td></tr><tr><td><strong>Laptop</strong></td><td>Portable full computer</td><td>Windows, macOS, Linux</td></tr><tr><td><strong>eReader</strong></td><td>Specialised for reading e-books</td><td>Custom (Kindle)</td></tr></tbody></table><hr><h2 id="mobile-operating-systems" tabindex="-1">Mobile Operating Systems <a class="header-anchor" href="#mobile-operating-systems" aria-label="Permalink to &quot;Mobile Operating Systems&quot;">​</a></h2><h3 id="android-google" tabindex="-1">Android (Google) <a class="header-anchor" href="#android-google" aria-label="Permalink to &quot;Android (Google)&quot;">​</a></h3><ul><li>Open source — manufacturers can customise it</li><li>Used by Samsung, Huawei, Xiaomi, and many others</li><li>Largest market share globally</li><li>Apps from Google Play Store</li><li>More customisable; slightly more malware risk due to sideloading</li></ul><h3 id="ios-apple" tabindex="-1">iOS (Apple) <a class="header-anchor" href="#ios-apple" aria-label="Permalink to &quot;iOS (Apple)&quot;">​</a></h3><ul><li>Closed source — only on Apple iPhones and iPads</li><li>Tightly controlled ecosystem</li><li>Apps only from Apple App Store (strict approval process)</li><li>Generally more secure and consistent updates</li><li>Less customisable</li></ul><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Android</th><th>iOS</th></tr></thead><tbody><tr><td>Manufacturer</td><td>Multiple (Samsung, Huawei, etc.)</td><td>Apple only</td></tr><tr><td>Source</td><td>Open source</td><td>Closed source</td></tr><tr><td>App store</td><td>Google Play</td><td>Apple App Store</td></tr><tr><td>Customisation</td><td>High</td><td>Limited</td></tr><tr><td>Market share</td><td>~72% global</td><td>~27% global</td></tr><tr><td>Updates</td><td>Varies by manufacturer</td><td>Guaranteed for years</td></tr><tr><td>Price range</td><td>Budget to premium</td><td>Premium only</td></tr></tbody></table><hr><h2 id="mobile-network-generations" tabindex="-1">Mobile Network Generations <a class="header-anchor" href="#mobile-network-generations" aria-label="Permalink to &quot;Mobile Network Generations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Generation</th><th>Speed</th><th>Latency</th><th>Key Feature</th></tr></thead><tbody><tr><td><strong>2G (GSM)</strong></td><td>~0.1 Mbps</td><td>High</td><td>Voice calls + SMS</td></tr><tr><td><strong>3G</strong></td><td>~2–42 Mbps</td><td>~100ms</td><td>Mobile internet</td></tr><tr><td><strong>4G LTE</strong></td><td>~10–150 Mbps</td><td>~30–50ms</td><td>HD video, mobile apps</td></tr><tr><td><strong>5G</strong></td><td>~100 Mbps–10 Gbps</td><td>&lt;10ms</td><td>IoT, autonomous vehicles, AR/VR</td></tr></tbody></table><h3 id="_4g-vs-5g" tabindex="-1">4G vs 5G <a class="header-anchor" href="#_4g-vs-5g" aria-label="Permalink to &quot;4G vs 5G&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>4G LTE</th><th>5G</th></tr></thead><tbody><tr><td>Max speed</td><td>~150 Mbps</td><td>~10 Gbps</td></tr><tr><td>Latency</td><td>30–50 ms</td><td>&lt;1 ms</td></tr><tr><td>Capacity</td><td>Moderate density</td><td>Very high device density</td></tr><tr><td>Infrastructure</td><td>Existing towers</td><td>New mmWave towers + existing</td></tr><tr><td>Coverage</td><td>Widespread</td><td>Still expanding (2024)</td></tr><tr><td>Use cases</td><td>Streaming, browsing</td><td>Autonomous vehicles, smart cities, AR</td></tr></tbody></table><hr><h2 id="advantages-of-mobile-computing" tabindex="-1">Advantages of Mobile Computing <a class="header-anchor" href="#advantages-of-mobile-computing" aria-label="Permalink to &quot;Advantages of Mobile Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Advantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Portability</strong></td><td>Work, communicate, access data from anywhere</td></tr><tr><td><strong>Always connected</strong></td><td>4G/5G/Wi-Fi — constant internet access</td></tr><tr><td><strong>GPS and location</strong></td><td>Navigation, location-based services</td></tr><tr><td><strong>Integrated camera</strong></td><td>Photography, video, document scanning</td></tr><tr><td><strong>Health monitoring</strong></td><td>Steps, heart rate, sleep tracking (wearables)</td></tr><tr><td><strong>Cloud sync</strong></td><td>Data backed up and accessible across all devices</td></tr><tr><td><strong>App ecosystem</strong></td><td>Millions of apps for every purpose</td></tr><tr><td><strong>Contactless payment</strong></td><td>Apple Pay, Google Pay — pay without a card</td></tr></tbody></table><hr><h2 id="disadvantages-and-limitations-of-mobile-computing" tabindex="-1">Disadvantages and Limitations of Mobile Computing <a class="header-anchor" href="#disadvantages-and-limitations-of-mobile-computing" aria-label="Permalink to &quot;Disadvantages and Limitations of Mobile Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limitation</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Battery life</strong></td><td>Powerful features drain battery; constant charging needed</td></tr><tr><td><strong>Small screen</strong></td><td>Limits usability for complex tasks</td></tr><tr><td><strong>Input method</strong></td><td>Touchscreen typing is slower than physical keyboard</td></tr><tr><td><strong>Processing power</strong></td><td>Less powerful than desktop/laptop for same price</td></tr><tr><td><strong>Storage</strong></td><td>Internal storage often limited (mitigated by cloud)</td></tr><tr><td><strong>Security risks</strong></td><td>Physical theft; malware apps; public Wi-Fi interception</td></tr><tr><td><strong>Connectivity dependence</strong></td><td>Many features unusable without internet</td></tr><tr><td><strong>Health concerns</strong></td><td>Eye strain, posture, radiation (minimal but debated)</td></tr><tr><td><strong>Distraction</strong></td><td>Notifications reduce focus and productivity</td></tr></tbody></table><hr><h2 id="mobile-security-threats" tabindex="-1">Mobile Security Threats <a class="header-anchor" href="#mobile-security-threats" aria-label="Permalink to &quot;Mobile Security Threats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>Description</th></tr></thead><tbody><tr><td><strong>Device theft</strong></td><td>Physical loss of device gives attacker access to data</td></tr><tr><td><strong>Malicious apps</strong></td><td>Apps that contain malware (especially from unofficial sources)</td></tr><tr><td><strong>Public Wi-Fi</strong></td><td>Unencrypted connections can be intercepted</td></tr><tr><td><strong>Phishing via SMS</strong></td><td>&quot;Smishing&quot; — fake text messages with malicious links</td></tr><tr><td><strong>Spyware</strong></td><td>Apps that secretly track location, messages, calls</td></tr><tr><td><strong>Ransomware</strong></td><td>Increasingly targeting mobile devices</td></tr></tbody></table><h3 id="mobile-security-best-practices" tabindex="-1">Mobile Security Best Practices <a class="header-anchor" href="#mobile-security-best-practices" aria-label="Permalink to &quot;Mobile Security Best Practices&quot;">​</a></h3><ul><li>Use a strong PIN, password, or biometric lock</li><li>Only install apps from official stores (Play Store / App Store)</li><li>Keep OS and apps updated</li><li>Use VPN on public Wi-Fi</li><li>Enable remote wipe (Find My iPhone / Find My Device)</li><li>Be cautious of app permissions — does a calculator need access to contacts?</li></ul><hr><h2 id="mobile-vs-desktop-for-different-tasks" tabindex="-1">Mobile vs Desktop for Different Tasks <a class="header-anchor" href="#mobile-vs-desktop-for-different-tasks" aria-label="Permalink to &quot;Mobile vs Desktop for Different Tasks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Better on Mobile</th><th>Better on Desktop</th></tr></thead><tbody><tr><td>Social media</td><td>✓</td><td></td></tr><tr><td>Navigation/GPS</td><td>✓</td><td></td></tr><tr><td>Photography</td><td>✓</td><td></td></tr><tr><td>Video editing</td><td></td><td>✓</td></tr><tr><td>Coding</td><td></td><td>✓</td></tr><tr><td>Spreadsheet work</td><td></td><td>✓</td></tr><tr><td>Quick communication</td><td>✓</td><td></td></tr><tr><td>Long-form writing</td><td></td><td>✓</td></tr></tbody></table><hr><h2 id="internet-of-things-iot" tabindex="-1">Internet of Things (IoT) <a class="header-anchor" href="#internet-of-things-iot" aria-label="Permalink to &quot;Internet of Things (IoT)&quot;">​</a></h2><p><strong>IoT</strong> is the network of physical objects embedded with sensors, software, and connectivity that allows them to collect and exchange data.</p><p><strong>Examples:</strong></p><ul><li>Smart home devices (lights, thermostat, locks)</li><li>Smart city traffic management</li><li>Wearable health monitors</li><li>Industrial sensors in factories</li><li>Smart agriculture (soil moisture sensors)</li></ul><p>IoT devices connect via Wi-Fi, Bluetooth, Zigbee, or 5G. 5G&#39;s low latency and high device density make it ideal for IoT.</p><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Mobile OS</strong></td><td>Operating system designed for touch-screen portable devices</td></tr><tr><td><strong>Android</strong></td><td>Open-source mobile OS by Google</td></tr><tr><td><strong>iOS</strong></td><td>Apple&#39;s closed-source mobile OS</td></tr><tr><td><strong>4G/LTE</strong></td><td>4th generation mobile network — fast mobile internet</td></tr><tr><td><strong>5G</strong></td><td>5th generation network — ultra-fast, ultra-low latency</td></tr><tr><td><strong>Latency</strong></td><td>Delay between sending a request and receiving a response</td></tr><tr><td><strong>IoT</strong></td><td>Internet of Things — connected physical devices</td></tr><tr><td><strong>Smishing</strong></td><td>SMS phishing — scam text messages</td></tr><tr><td><strong>Wearable</strong></td><td>Computer worn on body (watch, fitness band)</td></tr><tr><td><strong>Cloud sync</strong></td><td>Automatic copying of data to cloud storage</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give THREE advantages of mobile computing&quot;</strong> — portability, always connected, GPS, camera, cloud sync — always explain, don&#39;t just list</p></li><li><p><strong>&quot;Give THREE limitations/disadvantages of mobile computing&quot;</strong> — battery life, small screen, security risks, processing power, connectivity dependence</p></li><li><p><strong>&quot;Compare Android and iOS&quot;</strong> — open source vs closed; multiple manufacturers vs Apple only; customisation; app store control</p></li><li><p><strong>&quot;Compare 4G and 5G&quot;</strong> — speed (5G much faster), latency (5G &lt;10ms vs 4G 30–50ms), coverage (4G wider), use cases (5G enables IoT, autonomous vehicles)</p></li><li><p><strong>&quot;What is IoT? Give TWO examples.&quot;</strong> — network of physical objects with sensors and connectivity; examples: smart home devices, wearable health monitors, industrial sensors</p></li></ol></div>',48)])])}const m=e(d,[["render",i]]);export{p as __pageData,m as default};
